/**
 * Coding Challenge Generator Bot
 * Generates coding challenges using OpenCode CLI (same pattern as other bots)
 * Saves challenges to database as the source of truth
 * 
 * IMPORTANT: Expected outputs are generated by RUNNING the actual solution code,
 * not by AI generation. This ensures test cases are always correct.
 * 
 * Usage:
 *   node script/coding-challenge-bot.js
 * 
 * Environment variables:
 *   INPUT_DIFFICULTY - 'easy', 'medium', or 'random' (default: random)
 *   INPUT_CATEGORY - specific category or 'random' (default: random)
 *   INPUT_COUNT - number of challenges to generate (default: 1)
 */

import { writeGitHubOutput } from './utils.js';
import fs from 'fs';
import path from 'path';
import { generateChallengesParallel } from './ai/graphs/coding-challenge-graph.js';
import { categories as CATEGORIES, difficulties as DIFFICULTIES, topCompanies as TOP_COMPANIES } from './ai/prompts/templates/coding-challenge.js';

const CODING_CHALLENGES_FILE = path.join(process.cwd(), 'data', 'coding-challenges.json');

function readCodingChallenges() {
  try {
    if (fs.existsSync(CODING_CHALLENGES_FILE)) {
      return JSON.parse(fs.readFileSync(CODING_CHALLENGES_FILE, 'utf8'));
    }
  } catch {}
  return [];
}

function writeCodingChallenges(challenges) {
  const dir = path.dirname(CODING_CHALLENGES_FILE);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(CODING_CHALLENGES_FILE, JSON.stringify(challenges, null, 2));
}

// Get 2-4 random companies
function getRandomCompanies() {
  const count = Math.floor(Math.random() * 3) + 2; // 2-4 companies
  const shuffled = [...TOP_COMPANIES].sort(() => Math.random() - 0.5);
  return shuffled.slice(0, count);
}

// Initialize coding_challenges data file
async function initCodingChallengesTable() {
  console.log('📦 Ensuring coding_challenges data file exists...');
  
  // Ensure the file exists by reading (creates dir via writeCodingChallenges if needed)
  const existing = readCodingChallenges();
  writeCodingChallenges(existing);
  
  console.log('✅ Data file ready');
}

// Generate unique ID for coding challenge
async function generateChallengeId() {
  const challenges = readCodingChallenges();
  let maxNum = 0;
  for (const c of challenges) {
    const m = (c.id || '').match(/^cc(\d+)$/);
    if (m) {
      const num = parseInt(m[1], 10);
      if (num > maxNum) maxNum = num;
    }
  }
  return `cc${maxNum + 1}`;
}

// Check for duplicate challenge by title similarity (fuzzy match)
async function isDuplicateChallenge(title) {
  const normalizedTitle = title.toLowerCase().replace(/[^a-z0-9]/g, '');
  const challenges = readCodingChallenges();
  
  for (const c of challenges) {
    const existingNormalized = (c.title || '').toLowerCase().replace(/[^a-z0-9]/g, '');
    
    if (existingNormalized === normalizedTitle) {
      return true;
    }
    
    if (existingNormalized.includes(normalizedTitle) || normalizedTitle.includes(existingNormalized)) {
      const shorter = Math.min(existingNormalized.length, normalizedTitle.length);
      const longer = Math.max(existingNormalized.length, normalizedTitle.length);
      if (shorter / longer > 0.8) {
        return true;
      }
    }
  }
  
  return false;
}

// Get existing challenge titles for a category (for prompt context)
async function getExistingTitlesForCategory(category) {
  const challenges = readCodingChallenges();
  return challenges.filter(c => c.category === category).slice(0, 20).map(c => c.title);
}

// Save challenge to database
async function saveChallengeToDb(challenge) {
  const id = await generateChallengeId();
  const now = new Date().toISOString();
  
  const challenges = readCodingChallenges();
  challenges.push({
    id,
    title: challenge.title,
    description: challenge.description,
    difficulty: challenge.difficulty,
    category: challenge.category,
    tags: JSON.stringify(challenge.tags || []),
    companies: JSON.stringify(challenge.companies || []),
    starter_code_js: challenge.starterCode?.javascript || '',
    starter_code_py: challenge.starterCode?.python || '',
    test_cases: JSON.stringify(challenge.testCases),
    hints: JSON.stringify(challenge.hints || []),
    solution_js: challenge.sampleSolution?.javascript || '',
    solution_py: challenge.sampleSolution?.python || '',
    complexity_time: challenge.complexity?.time || 'O(n)',
    complexity_space: challenge.complexity?.space || 'O(1)',
    complexity_explanation: challenge.complexity?.explanation || '',
    time_limit: challenge.timeLimit || 15,
    created_at: now,
    last_updated: now
  });
  writeCodingChallenges(challenges);
  
  return id;
}

// Get count of challenges in database
async function getChallengeCount() {
  return readCodingChallenges().length;
}

async function main() {
  console.log('=== 🤖 Coding Challenge Generator Bot ===\n');

  // Parse CLI args
  const args = process.argv.slice(2);
  const dryRun = args.includes('--dry-run');
  const countArg = args.find(a => a.startsWith('--count='))?.split('=')[1];
  const diffArg = args.find(a => a.startsWith('--difficulty='))?.split('=')[1];
  const catArg = args.find(a => a.startsWith('--category='))?.split('=')[1];

  if (dryRun) console.log('🔍 DRY RUN MODE - no DB writes\n');

  // Initialize database table
  if (!dryRun) await initCodingChallengesTable();
  
  const initialCount = dryRun ? 0 : await getChallengeCount();
  if (!dryRun) console.log(`📊 Current challenges in database: ${initialCount}`);
  
  const inputDifficulty = diffArg || process.env.INPUT_DIFFICULTY || 'random';
  const inputCategory = catArg || process.env.INPUT_CATEGORY || 'random';
  const inputCount = parseInt(countArg || process.env.INPUT_COUNT || '1', 10);
  
  console.log(`\nConfiguration:`);
  console.log(`  Difficulty: ${inputDifficulty}`);
  console.log(`  Category: ${inputCategory}`);
  console.log(`  Count: ${inputCount}`);
  
  const generated = [];
  const failed = [];

  // Build task list
  const challenges = await Promise.all(Array.from({ length: inputCount }, async () => {
    const difficulty = inputDifficulty === 'random'
      ? DIFFICULTIES[Math.floor(Math.random() * DIFFICULTIES.length)]
      : inputDifficulty;
    const category = inputCategory === 'random'
      ? CATEGORIES[Math.floor(Math.random() * CATEGORIES.length)]
      : inputCategory;
    const companies = getRandomCompanies();
    const existingTitles = dryRun ? [] : await getExistingTitlesForCategory(category);
    return { difficulty, category, companies, existingTitles };
  }));

  const poolResults = await generateChallengesParallel(challenges);

  for (const task of poolResults.completed) {
    const challenge = task.result?.challenge;
    if (!challenge) { failed.push({ reason: task.result?.error || 'No result' }); continue; }
    if (dryRun) { generated.push(challenge); continue; }
    if (await isDuplicateChallenge(challenge.title)) {
      failed.push({ reason: 'Duplicate title' }); continue;
    }
    try {
      const challengeId = await saveChallengeToDb(challenge);
      challenge.id = challengeId;
      generated.push(challenge);
      console.log(`✅ Saved: ${challengeId} — ${challenge.title}`);
    } catch (dbError) {
      failed.push({ reason: `DB error: ${dbError.message}` });
    }
  }
  for (const task of poolResults.failed) {
    failed.push({ reason: task.error || 'Failed' });
  }
  
  const finalCount = dryRun ? 0 : await getChallengeCount();
  
  // Summary
  console.log('\n=== SUMMARY ===');
  console.log(`Generated: ${generated.length}/${inputCount}`);
  console.log(`Failed: ${failed.length}`);
  if (!dryRun) console.log(`Total challenges in database: ${finalCount}`);
  
  if (generated.length > 0) {
    console.log('\n✅ Added Challenges:');
    generated.forEach((c, i) => {
      console.log(`  ${i + 1}. [${c.id || 'dry-run'}] ${c.title} (${c.difficulty}, ${c.category})`);
    });
  }
  
  if (failed.length > 0) {
    console.log('\n❌ Failed:');
    failed.forEach(f => console.log(`  - ${f.category} (${f.difficulty}): ${f.reason}`));
  }

  if (!dryRun) {
    writeGitHubOutput({
      generated_count: generated.length,
      failed_count: failed.length,
      total_challenges: finalCount,
      added_ids: generated.map(c => c.id).join(',')
    });
  }
}

main().catch(e => {
  console.error('Fatal error:', e);
  process.exit(1);
});
